-- Migration: Seed issues batch 3 (issues 9-12)

INSERT INTO issues (rank, slug, icon, severity, title, anchor_stat, short_desc, definition, australian_data, mechanisms, impacts, groups, sources) VALUES
(9, 'school-refusal', '🚪', 'high',
 'School Refusal & Emotionally Based Absence',
 'Post-pandemic spike in school refusal documented nationally — Parliamentary Library 2022–23',
 'School refusal is not defiance. It is fear. Distinguishing emotionally-based school avoidance from truancy is critical to getting the response right — and many schools still don''t make this distinction.',
 'School refusal (emotionally-based school avoidance) refers to severe difficulty attending school associated with emotional distress — particularly anxiety, depression, and somatic symptoms. It is explicitly distinguished from truancy (wilful absence) in academic and policy literature. The child often wants to attend but is overwhelmed by distress.',
 'The Australian Parliamentary Library Research Paper (2022–23) defines school refusal, notes the post-pandemic surge, and highlights the distinction from truancy. School refusal affects an estimated 1–5% of students at any given time and is most common at key transition points. Anxiety is the most common underlying driver nationally.',
 'School environments contain multiple anxiety triggers: performance assessment, social evaluation, unpredictability, and authority relationships. When anxiety is severe enough, the avoidance response becomes overwhelming. Morning escalation into panic attacks and somatic symptoms are common presentations. The longer avoidance continues, the harder return becomes.',
 '[{"title":"Learning Loss","text":"Extended school refusal episodes cause severe curriculum gaps and declining academic confidence."},{"title":"Family Stress","text":"School refusal places intense pressure on parents — work disruption, guilt, and helplessness."},{"title":"Social Skills","text":"Missed peer interaction stunts social development during critical adolescent years."},{"title":"Misdiagnosis","text":"Children labelled ''truants'' when experiencing refusal receive punishment rather than the support they need."}]'::jsonb,
 '["Students with anxiety disorders","Students with ASD or sensory sensitivities","Year 7 transition students","Students who have experienced bullying","Children of anxious parents"]'::jsonb,
 '["Parliamentary Library Research Paper 2022–23 — School Refusal","Young Minds Matter anxiety prevalence data","Australian Institute of Family Studies"]'::jsonb),

(10, 'sleep-deprivation', '💤', 'high',
 'Sleep Deprivation & Fatigue',
 '25% of 12–13 yr olds and 50% of 16–17 yr olds miss sleep guidelines on school nights',
 'Sleep deprivation is quietly undermining the cognitive capacity of Australian teenagers. A tired student is physically present in the classroom but neurologically compromised.',
 'Sleep guidelines recommend 9–11 hours for children aged 6–12 and 8–10 hours for teenagers 13–17. AIHW uses self-reported and device-based data. ''School night'' sleep is the critical measure, given the direct link between insufficient sleep and next-day cognitive performance.',
 'AIHW reports that one-quarter of 12–13 year olds and approximately half of 16–17 year olds do not meet recommended sleep guidelines on school nights. This is strongly linked to smartphone and screen use. Among older teens, the prevalence is almost a majority — a structural problem, not an individual failing.',
 'Sleep is when the brain consolidates memory from the school day. REM sleep processes emotional experiences. Sleep deprivation impairs the prefrontal cortex (executive function, impulse control, decision-making) while heightening amygdala emotional reactivity. A sleep-deprived student is more irritable, less able to concentrate, and more likely to experience depressive symptoms.',
 '[{"title":"Memory Consolidation","text":"Sleep deprivation prevents the consolidation needed to retain lessons learned during the school day."},{"title":"Emotional Regulation","text":"Tired students are more irritable, reactive, and prone to conflict with peers and teachers."},{"title":"Mental Health","text":"Chronic sleep loss is bidirectionally linked to anxiety and depression in adolescents."},{"title":"Physical Health","text":"Insufficient sleep impacts immune function, weight regulation, and physical development."}]'::jsonb,
 '["Teenagers aged 14–17 (highest deficit)","Students on social media platforms","Students with anxiety or depression","Students in early-start schools","Students with heavy gaming habits"]'::jsonb,
 '["AIHW Sleep Problems as a Risk Factor","Black Dog Institute Teens & Screens 2024","National Sleep Foundation Age-Based Guidelines"]'::jsonb),

(11, 'screens-social-media', '📲', 'high',
 'Screens, Social Media & Mental Health Load',
 'Black Dog Institute 2024: Australian adolescent screen use is creating measurable mental health burden',
 'Australian research now documents the link between high social media use and adolescent mental health deterioration. The evidence has moved past debate — but the solutions remain actively contested.',
 'Screen-related mental health load refers to the psychological burden created by excessive or problematic use of smartphones, social media, gaming, and streaming. This includes social comparison, fear of missing out, cyberbullying exposure, sleep disruption, and displacement of face-to-face socialisation.',
 'The Black Dog Institute''s 2024 report using Australian adolescent data documents associations between high social media use and elevated rates of depression, anxiety, and poor self-image. The eSafety Commissioner reports near-universal platform use among teenagers, with high exposure to harmful content creating a compounding mental health load.',
 'Social media platforms are designed to maximise engagement using variable reward systems that exploit the dopamine reward pathway. Adolescent brains — whose reward circuits are more active and executive function still developing — are particularly susceptible. Social comparison operates constantly; status signals (likes, followers) create real anxiety. Algorithmic personalisation accelerates exposure to harmful content.',
 '[{"title":"Social Comparison","text":"Constant comparison to curated peer images is a leading driver of body dissatisfaction and low self-worth."},{"title":"Attention Span","text":"Short-form content consumption makes sustained classroom learning progressively harder."},{"title":"Sleep Displacement","text":"Late-night scrolling is the primary driver of adolescent sleep deficit in Australia."},{"title":"Relationship Quality","text":"Time online displaces the face-to-face interaction needed for social skill development."}]'::jsonb,
 '["Girls aged 12–17 (highest social media harm)","Teens with pre-existing anxiety","Students with ADHD","Students with limited offline social support","Boys in gaming-heavy environments"]'::jsonb,
 '["Black Dog Institute Teens & Screens Report 2024","eSafety Commissioner Online Experiences Research","AIHW Adolescent Health Indicators"]'::jsonb),

(12, 'academic-stress', '📚', 'high',
 'Stress & Academic Workload Pressure',
 'Australian PISA 2022 documents student exposure to stress and performance pressure as education risk factors',
 'Academic pressure is developmentally appropriate in small doses. In Australian secondary schools — particularly Years 11–12 — it has become a crisis of chronic, sustained stress.',
 'Academic stress refers to the psychological pressure created by perceived demands exceeding coping resources in the school context. Key drivers include examinations, grades, ATAR expectations, parental pressure, peer competition, and perceived consequences of failure.',
 'PISA 2022 data, reported by ACER for Australia, includes student experience constructs such as stress resistance and test anxiety. Mission Australia 2024 identifies mental health challenges as a barrier to achieving personal goals for one in five young Australians across all states and territories.',
 'Chronic academic stress activates the hypothalamic-pituitary-adrenal (HPA) axis, releasing cortisol. Short-term, this can enhance performance. Chronically, it damages hippocampal memory, impairs immune function, disrupts sleep, and creates a vicious cycle where stress impairs performance, which in turn increases stress.',
 '[{"title":"Physical Health","text":"Chronic stress causes headaches, stomach problems, and weakened immunity in students."},{"title":"Sleep Quality","text":"Academic rumination — worrying about school at night — is a primary driver of teen insomnia."},{"title":"Relationship Quality","text":"Overwhelmed students withdraw from family and peer connection, compounding isolation."},{"title":"Learning Paradox","text":"Severe stress actually impairs the very cognitive functions needed to study effectively."}]'::jsonb,
 '["Year 11–12 students under ATAR pressure","Students in selective/high-achieving schools","First-generation tertiary aspiration students","Students with perfectionist traits","Children of high-expectation parents"]'::jsonb,
 '["ACER PISA 2022 Australia Volume II — Student Wellbeing","Mission Australia Youth Survey 2024","Australian Association of Psychologists — exam stress research"]'::jsonb);
